#include <iostream>
#include <cstdarg>

int sumN(int count, ...) {
    va_list args;
    va_start(args, count);
    int total = 0;
    for (int i = 0; i < count; ++i)
        total += va_arg(args, int);
    va_end(args);
    return total;
}

int main() {
    int n;
    std::cin >> n;
    int a[5] = {};
    for (int i = 0; i < n; ++i)
        std::cin >> a[i];

    int result = 0;
    if      (n == 1) result = sumN(1, a[0]);
    else if (n == 2) result = sumN(2, a[0], a[1]);
    else if (n == 3) result = sumN(3, a[0], a[1], a[2]);
    else if (n == 4) result = sumN(4, a[0], a[1], a[2], a[3]);
    else             result = sumN(5, a[0], a[1], a[2], a[3], a[4]);

    std::cout << result << "\n";
    return 0;
}

