#include <iostream>
#include <cstdarg>

int maxN(int count, ...) {
    va_list args;
    va_start(args, count);
    int best = va_arg(args, int);
    for (int i = 1; i < count; ++i) {
        int val = va_arg(args, int);
        if (val > best) best = val;
    }
    va_end(args);
    return best;
}

int main() {
    int n;
    std::cin >> n;
    int a[5] = {};
    for (int i = 0; i < n; ++i)
        std::cin >> a[i];

    int result = 0;
    if      (n == 1) result = maxN(1, a[0]);
    else if (n == 2) result = maxN(2, a[0], a[1]);
    else if (n == 3) result = maxN(3, a[0], a[1], a[2]);
    else if (n == 4) result = maxN(4, a[0], a[1], a[2], a[3]);
    else             result = maxN(5, a[0], a[1], a[2], a[3], a[4]);

    std::cout << result << "\n";
    return 0;
}
